import type { PaperclipPluginManifestV1 } from "@paperclipai/plugin-sdk";

const PLUGIN_ID = "paperclip.vnc-browser";
const PLUGIN_VERSION = "1.0.0";
const PAGE_SLOT_ID = "vnc-browser-page";
const PAGE_EXPORT_NAME = "BrowserPanel";

/**
 * Manifest for the VNC browser page plugin.
 * Provides a full-page live browser view using noVNC.
 */
const manifest: PaperclipPluginManifestV1 = {
  id: PLUGIN_ID,
  apiVersion: 1,
  version: PLUGIN_VERSION,
  displayName: "Live Browser",
  description: "Watch and interact with agents browsing the web in real-time via a shared Chromium instance.",
  author: "Paperclip",
  categories: ["ui"],
  capabilities: ["ui.page.register"],
  entrypoints: {
    worker: "./dist/worker.js",
    ui: "./dist/ui",
  },
  ui: {
    slots: [
      {
        type: "page",
        id: PAGE_SLOT_ID,
        displayName: "Live Browser",
        exportName: PAGE_EXPORT_NAME,
      },
    ],
  },
};

export default manifest;
===WORKER===
import { definePlugin, runWorker } from "@paperclipai/plugin-sdk";

const PLUGIN_NAME = "vnc-browser";

const plugin = definePlugin({
  async setup(ctx) {
    ctx.logger.info(`${PLUGIN_NAME} plugin setup complete`);
  },

  async onHealth() {
    return { status: "ok", message: "VNC browser plugin ready" };
  },
});

export default plugin;
runWorker(plugin, import.meta.url);
===BROWSERPANEL===
import React, { useState, useEffect } from "react";

interface BrowserStatus {
  running: boolean;
  cdp: boolean;
}

/**
 * BrowserPanel — Live browser page plugin component.
 *
 * Polls /api/browser/status every 3 seconds and renders a noVNC iframe
 * when Chromium + websockify are ready.
 */
export function BrowserPanel() {
  const [status, setStatus] = useState<BrowserStatus | null>(null);
  const [loading, setLoading] = useState(false);

  const loadStatus = () =>
    fetch("/api/browser/status")
      .then((r) => r.json() as Promise<BrowserStatus>)
      .then(setStatus)
      .catch(() => {});

  useEffect(() => {
    void loadStatus();
    const iv = setInterval(() => { void loadStatus(); }, 3000);
    return () => clearInterval(iv);
  }, []);

  const start = async () => {
    setLoading(true);
    await fetch("/api/browser/start", { method: "POST" }).catch((e: Error) =>
      alert(e.message),
    );
    // Poll until CDP is ready (up to 20 seconds)
    for (let i = 0; i < 20; i++) {
      await new Promise<void>((r) => setTimeout(r, 1000));
      const s = await fetch("/api/browser/status")
        .then((r) => r.json() as Promise<BrowserStatus>)
        .catch(() => null);
      if (s?.cdp) {
        setStatus(s);
        break;
      }
      if (s) setStatus(s);
    }
    setLoading(false);
  };

  const stop = async () => {
    setLoading(true);
    await fetch("/api/browser/stop", { method: "POST" }).catch((e: Error) =>
      alert(e.message),
    );
    await new Promise<void>((r) => setTimeout(r, 1500));
    await loadStatus();
    setLoading(false);
  };

  const running = status?.running;
  const cdpReady = status?.cdp;

  return (
    <div>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: 16,
        }}
      >
        <div>
          <h2 style={{ fontSize: 16, marginBottom: 4 }}>Live Browser</h2>
          <div style={{ fontSize: 12, color: "#555" }}>
            Shared Chromium instance — agents connect to this browser when running tasks.
            Your session data (cookies, logins) persists across restarts.
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <div
              style={{
                width: 8,
                height: 8,
                borderRadius: "50%",
                background: cdpReady ? "#4caf50" : running ? "#ff9800" : "#555",
              }}
            />
            <span style={{ fontSize: 12, color: "#888" }}>
              {status === null
                ? "checking\u2026"
                : cdpReady
                ? "ready"
                : running
                ? "starting\u2026"
                : "dormant"}
            </span>
          </div>
          {!running ? (
            <button className="primary" onClick={() => { void start(); }} disabled={loading}>
              {loading ? "starting\u2026" : "Start Browser"}
            </button>
          ) : (
            <button onClick={() => { void stop(); }} disabled={loading}>
              {loading ? "stopping\u2026" : "Make Dormant"}
            </button>
          )}
        </div>
      </div>

      {running ? (
        <div
          style={{
            background: "#0a0a0a",
            border: "1px solid #2a2a2a",
            borderRadius: 4,
            overflow: "hidden",
          }}
        >
          {!cdpReady && (
            <div style={{ padding: "12px 16px", color: "#ff9800", fontSize: 12 }}>
              Browser is starting, please wait\u2026
            </div>
          )}
          {cdpReady && (
            <iframe
              src="/vnc/vnc_lite.html?path=vnc/websockify&autoconnect=1&resize=scale&compression_level=2&quality_level=6"
              style={{
                width: "100%",
                height: "calc(100vh - 180px)",
                border: "none",
                display: "block",
              }}
              title="Live Browser"
            />
          )}
        </div>
      ) : (
        <div
          style={{
            background: "#0d0d0d",
            border: "1px solid #1a1a1a",
            borderRadius: 4,
            padding: 40,
            textAlign: "center",
          }}
        >
          <div style={{ color: "#444", fontSize: 13, marginBottom: 8 }}>
            Browser is dormant \u2014 no resources in use
          </div>
          <div style={{ color: "#333", fontSize: 12 }}>
            Click \u201cStart Browser\u201d to launch Chromium. Agents will automatically use this browser
            instead of a headless instance, so you can watch and interact while they work.
          </div>
        </div>
      )}

      <div style={{ marginTop: 12, fontSize: 11, color: "#444" }}>
        You can click and type directly in the browser above. The agent drives the same browser \u2014
        useful for handling MFA, CAPTCHAs, or anything it gets stuck on. Logins and cookies are
        saved to <code>/data/chrome-profile</code>. Set{" "}
        <code>MC_VNC_AUTOSTART=true</code> to start automatically on container restart.
      </div>
    </div>
  );
}
===VNC-WS-PROXY===
import type { Server as HttpServer } from "node:http";
import net from "node:net";
import { logger } from "../middleware/logger.js";

const VNC_WEBSOCKIFY_PATH = "/vnc/websockify";
const WEBSOCKIFY_PORT = 6080;
const WEBSOCKIFY_HOST = "127.0.0.1";

/**
 * Proxies /vnc/websockify WebSocket upgrades directly to the local
 * websockify TCP server on port 6080, without a full ws dependency.
 */
export function setupVncWebSocketProxy(server: HttpServer): void {
  server.prependListener("upgrade", (req, socket, head) => {
    if (!(req.url ?? "").startsWith(VNC_WEBSOCKIFY_PATH)) return;

    // Perform the HTTP 101 handshake manually then pipe raw TCP.
    const key = req.headers["sec-websocket-key"] as string;
    if (!key) { socket.destroy(); return; }

    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const crypto = require("node:crypto") as typeof import("node:crypto");
    const accept = crypto
      .createHash("sha1")
      .update(key + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11")
      .digest("base64");

    const handshake = [
      "HTTP/1.1 101 Switching Protocols",
      "Upgrade: websocket",
      "Connection: Upgrade",
      `Sec-WebSocket-Accept: ${accept}`,
      "",
      "",
    ].join("\r\n");

    socket.write(handshake);
    if (head?.length) socket.unshift(head);

    const tcp = net.connect(WEBSOCKIFY_PORT, WEBSOCKIFY_HOST);

    tcp.on("error", (err) => {
      logger.warn({ err }, "vnc-ws-proxy: failed to connect to websockify");
      socket.destroy();
    });

    socket.on("error", () => tcp.destroy());
    socket.pipe(tcp);
    tcp.pipe(socket);
  });
}
===BROWSER-ROUTE===
import { Router } from "express";
import { exec, spawn } from "node:child_process";

const router = Router();

const SCRIPTS_DIR = "/app/scripts";

function vncRunning(): Promise<boolean> {
  return new Promise((resolve) => {
    exec("ss -tln | grep -q ':5900 '", (err) => resolve(!err));
  });
}

function chromiumReady(): Promise<boolean> {
  return new Promise((resolve) => {
    exec(
      "curl -s --max-time 2 http://127.0.0.1:9222/json/version > /dev/null 2>&1",
      (err) => resolve(!err),
    );
  });
}

function websockifyReady(): Promise<boolean> {
  return new Promise((resolve) => {
    exec("ss -tln | grep -q ':6080 '", (err) => resolve(!err));
  });
}

// GET /api/browser/status
router.get("/status", async (_req, res) => {
  const running = await vncRunning();
  const cdp = running ? (await chromiumReady()) && (await websockifyReady()) : false;
  res.json({ running, cdp });
});

// POST /api/browser/start
router.post("/start", (_req, res) => {
  const child = spawn("bash", [`${SCRIPTS_DIR}/vnc-start.sh`], {
    detached: true,
    stdio: "ignore",
  });
  child.unref();
  res.json({
    ok: true,
    message: "VNC stack starting — poll /status for readiness",
  });
});

// POST /api/browser/stop
router.post("/stop", (_req, res) => {
  exec(`${SCRIPTS_DIR}/vnc-stop.sh`, { timeout: 10000 }, (_err, stdout) => {
    res.json({ ok: true, message: (stdout ?? "").trim() });
  });
});

export default router;

